  ('elementary-f29af906-moex-00934', 'elementary-f29af906', 'elementary-f29af906-moex-110-20d8901b', 'sub-elementary-f29af906-04', NULL, 'single_choice', '依土地登記規則之規定，關於申請區分所有建物所有權第一次登記，下列敘述何者錯誤？', '["區分所有建物申請登記時，應檢具全體起造人就專有部分所屬各共有部分及基地權利應有部分之分配 文件", "區分所有權人申請建物所有權第一次登記，登記機關受理時，應於建物登記簿所有權部適當欄記明基 地權利種類及範圍", "區分所有建物共有部分之登記僅建立標示部及加附區分所有建物共有部分附表，其建號、總面積及權 利範圍，應於各專有部分之建物所有權狀中記明之，不另發給所有權狀", "區分所有建物，區分所有權人得就其專有部分及所屬共有部分之權利，單獨申請建物所有權第一次登記"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:56+00:00", "source_pdf_sha1": "753edbff8c70", "answer_pdf_sha1": "09eb751b23b0", "source_family": "moex-gov-tw", "moex": {"exam_code": "110010", "c": "514", "s": "0306", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "土地行政大意", "year": "110", "exam_name": "110年公務人員初等考試", "original_question_number": 8, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "地政"}'::jsonb, NULL),
